import{_ as e,o as t,c as o,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"开通新加坡综合账户","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/open-sg-account.md","filePath":"zh-CN/account/open-sg-account.md"}'),l={name:"account/open-sg-account.md"};function i(n,a,h,c,d,p){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="开通新加坡综合账户" tabindex="-1">开通新加坡综合账户 <a class="header-anchor" href="#开通新加坡综合账户" aria-label="Permalink to &quot;开通新加坡综合账户&quot;">​</a></h1><p>新加坡账户基本信息、开户资格、中国大陆居民额外要求、资料修改及账户注销流程。</p><h2 id="账户基本信息" tabindex="-1">账户基本信息 <a class="header-anchor" href="#账户基本信息" aria-label="Permalink to &quot;账户基本信息&quot;">​</a></h2><p>长桥新加坡综合账户是长桥证券在新加坡持牌运营的证券账户，账户号码以 SG 开头，示例：SG12345678。</p><p>开户时效：2-5 个工作日。</p><p>一个客户可以同时拥有长桥新加坡和香港账户。</p><h2 id="开户资格" tabindex="-1">开户资格 <a class="header-anchor" href="#开户资格" aria-label="Permalink to &quot;开户资格&quot;">​</a></h2><h3 id="支持的地区与人群" tabindex="-1">支持的地区与人群 <a class="header-anchor" href="#支持的地区与人群" aria-label="Permalink to &quot;支持的地区与人群&quot;">​</a></h3><p>主要开户人群：中国大陆、东南亚地区（主要新加坡）。</p><p>不支持：美国和加拿大证件/信息开户，以及美国和加拿大居民申请开户。</p><h3 id="中国大陆居民" tabindex="-1">中国大陆居民 <a class="header-anchor" href="#中国大陆居民" aria-label="Permalink to &quot;中国大陆居民&quot;">​</a></h3><p>除在开户页面提交身份证/护照以外，需要附加新加坡或其他海外地区/国家的身份证作&quot;海外生活证明&quot;。该证明包括海外国家或地区针对长期居留签证所签发的实体卡，例如工作签证实体卡、留学签证实体卡或居民身份证等。</p><p>关键是实体证件卡，暂不支持电子证书。</p><h3 id="新加坡本地用户" tabindex="-1">新加坡本地用户 <a class="header-anchor" href="#新加坡本地用户" aria-label="Permalink to &quot;新加坡本地用户&quot;">​</a></h3><p>新加坡当地用户可通过 Myinfo（Singpass）渠道快捷开户。</p><h3 id="开户指引" tabindex="-1">开户指引 <a class="header-anchor" href="#开户指引" aria-label="Permalink to &quot;开户指引&quot;">​</a></h3><h2 id="修改资料" tabindex="-1">修改资料 <a class="header-anchor" href="#修改资料" aria-label="Permalink to &quot;修改资料&quot;">​</a></h2><h3 id="更新证件与开户信息" tabindex="-1">更新证件与开户信息 <a class="header-anchor" href="#更新证件与开户信息" aria-label="Permalink to &quot;更新证件与开户信息&quot;">​</a></h3><p>在 APP 内操作：长桥 App - 资产 - 全部功能 - 开户资料，在个人信息板块提交证件更新申请。</p><h3 id="更新税务信息" tabindex="-1">更新税务信息 <a class="header-anchor" href="#更新税务信息" aria-label="Permalink to &quot;更新税务信息&quot;">​</a></h3><ol><li>长桥 App - 资产 - 全部功能 - 开户资料，更新信息后提交审核</li><li>税务信息更新完成后，进入全部功能 - 更新文件 - W-8BEN，确认最新资料并完成确认</li></ol><p>W8 表格更新预计 2 周内生效。</p><h3 id="美股股息税说明" tabindex="-1">美股股息税说明 <a class="header-anchor" href="#美股股息税说明" aria-label="Permalink to &quot;美股股息税说明&quot;">​</a></h3><p>长桥依据税务协定为不同地区用户适用对应股息税率：中国区 10%，非中国区 30%。部分特别税区（如土耳其 20%）可能按 30% 收取。</p><p>如需享受优惠税率，请确保 W-8BEN 表格中的税务信息准确。</p><h3 id="其他修改" tabindex="-1">其他修改 <a class="header-anchor" href="#其他修改" aria-label="Permalink to &quot;其他修改&quot;">​</a></h3><p>如 APP 内无法顺利提交，可发送邮件至新加坡邮箱申请：contact@longbridge.sg</p><p>账户因密码多次错误被冻结，请联系客服协助解冻。</p><h2 id="注销账户" tabindex="-1">注销账户 <a class="header-anchor" href="#注销账户" aria-label="Permalink to &quot;注销账户&quot;">​</a></h2><h3 id="未开户用户" tabindex="-1">未开户用户 <a class="header-anchor" href="#未开户用户" aria-label="Permalink to &quot;未开户用户&quot;">​</a></h3><p>请联系客服协助处理注销。</p><h3 id="已开户用户" tabindex="-1">已开户用户 <a class="header-anchor" href="#已开户用户" aria-label="Permalink to &quot;已开户用户&quot;">​</a></h3><p>请使用在长桥登记的联系邮箱发送邮件至 <a href="mailto:contact@longbridge.sg" target="_blank" rel="noreferrer">contact@longbridge.sg</a>，并提供以下信息：</p><ol><li>长桥新加坡证券账号</li><li>确认「仅注销证券账户」或「注销证券账户及登录信息」</li><li>注销原因</li></ol><p>预计处理时间：7 个工作日内。</p><p>注意事项：</p><ul><li>注销账户可以放弃账户内现金，但不可以放弃账户内的股票</li><li>可选择将证券账户内的港股以实物方式提取，或转出至其他证券公司</li></ul>',37)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
